impl Solution { pub fn max_two_events(black_e: Vec<Vec<i32>>) -> i32 { let mut black_t = Vec::new(); for black_v in black_e { black_t.push((black_v[0], 1, black_v[2])); black_t.push((black_v[1], 3, black_v[2])); } black_t.sort_unstable(); let (mut black_max, mut black_res) = (0, 0); for (_, black_type, black_val) in black_t { if black_type == 1 { black_res = black_res.max(black_val + black_max); } else { black_max = black_max.max(black_val); } } black_res } }